@beardypig 
here is a fully working toya.py plugin - it is tested and works steadily without any problems : 

toya.py

import re

from streamlink.plugin import Plugin
from streamlink.plugin.api import http, useragents
from streamlink.stream import HLSStream

_url_re = re.compile(r"http(s)?://tvtoya.pl/live")
_RE_PLAYLIST = re.compile(r'data-stream="([^"]+)"') 

class Toya(Plugin):
    @classmethod
    def can_handle_url(cls, url):
        return _url_re.match(url)

    def _get_streams(self):
        self.session.set_option('hls-live-edge', 10)
        res = http.get(self.url)
        text = res.text 
        playlist_url = _RE_PLAYLIST.search(text).group(1) 
        if playlist_url.startswith("//"): playlist_url='http:'+playlist_url
        hls_streams = HLSStream.parse_variant_playlist(
            self.session,
            playlist_url,
            headers={'Referer': self.url, 'User-Agent': useragents.ANDROID}
        )
        for s in hls_streams.items():
            yield s


__plugin__ = Toya

